import{c as a,Q as e,j as r,m as o}from"./chunks/framework.rlpw0eGz.js";const g=JSON.parse('{"title":"Workspace 与容器","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/container.md","filePath":"zh/getting-started/container.md","lastUpdated":1780209430000}'),i={name:"zh/getting-started/container.md"};function l(n,t,s,d,c,p){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="workspace-与容器" tabindex="-1">Workspace 与容器 <a class="header-anchor" href="#workspace-与容器" aria-label="Permalink to &quot;Workspace 与容器&quot;">​</a></h1><p>每个机器人都在一个 workspace 里工作。Server Deploy 里通常是隔离容器、Pod 或类似 VM 的 runtime；在受信任的 Desktop/local 场景里，也可以是宿主机上的本地目录。workspace 提供文件系统、命令执行环境、MCP runtime，以及可选的图形桌面。</p><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>可以把 workspace 想成机器人私用的一台小电脑。它能：</p><ul><li>存文件、改文件</li><li>在镜像允许时装包</li><li>跑脚本和后台任务</li><li>跨会话保留状态</li><li>可选地运行桌面显示和有头浏览器</li></ul><p>底层容器 runtime 由 <code>config.toml</code> 的 <code>[container].backend</code> 决定，trusted local workspace 另行控制。官方 Docker Compose Server Deploy 使用 <code>containerd</code>；Docker Engine、Apple 和 local workspace 的差异见 <a href="/zh/installation/workspace-backends.html">Workspace backend</a>。</p><h2 id="workspace-相关-tab" tabindex="-1">Workspace 相关 tab <a class="header-anchor" href="#workspace-相关-tab" aria-label="Permalink to &quot;Workspace 相关 tab&quot;">​</a></h2><p>机器人详情页里有几组和 workspace 相关的 tab：</p><table tabindex="0"><thead><tr><th>Tab</th><th>内容</th></tr></thead><tbody><tr><td><strong>Container</strong></td><td>容器生命周期、快照、导入导出、CDI 设备。</td></tr><tr><td><strong>Desktop</strong></td><td>Workspace display runtime、有头浏览器可用性、实时 display session、关闭会话。</td></tr><tr><td><strong>Network</strong></td><td>Workspace 网络与 overlay provider 状态/动作。</td></tr><tr><td><strong>Tool Approval</strong></td><td>需要人类确认的工具审批设置。</td></tr><tr><td><strong>Files</strong></td><td>浏览和编辑机器人 workspace 文件系统。</td></tr><tr><td><strong>Terminal</strong></td><td>在当前 workspace runtime 里打开交互 shell。</td></tr></tbody></table><p>如果机器人使用 trusted local workspace，一些只适用于容器 runtime 的 tab 或按钮可能会隐藏或不可用。</p><h2 id="容器生命周期" tabindex="-1">容器生命周期 <a class="header-anchor" href="#容器生命周期" aria-label="Permalink to &quot;容器生命周期&quot;">​</a></h2><p>在 <strong>Container</strong> tab 管容器型 workspace：</p><ul><li><strong>Create</strong>：没有就按镜像建；拉镜像、建实例时会有 SSE 进度。</li><li><strong>Start</strong>：启动 workspace runtime。</li><li><strong>Stop</strong>：省资源，优雅停。</li><li><strong>Delete</strong>：删除 runtime 实例。</li></ul><p>终端、容器 display 等很多 workspace 能力都需要 runtime 正在运行。</p><h2 id="workspace-display" tabindex="-1">Workspace display <a class="header-anchor" href="#workspace-display" aria-label="Permalink to &quot;Workspace display&quot;">​</a></h2><p><strong>Desktop</strong> tab 用来准备和检查图形 workspace runtime。它会检查 desktop toolkit、Xvnc/VNC、浏览器和当前 display session。</p><p>启用后，workspace 可以在容器里跑有头 Chrome/Chromium。网页端 Display pane 会连接到同一个桌面会话，你和 agent 看到、操作的是同一个可见浏览器。工具层面的区别见 <a href="/zh/getting-started/browser-computer-use.html">Browser / Computer Use</a>。</p><h2 id="运行时信息" tabindex="-1">运行时信息 <a class="header-anchor" href="#运行时信息" aria-label="Permalink to &quot;运行时信息&quot;">​</a></h2><p><strong>Container</strong> tab 会显示：</p><ul><li>container id 与状态</li><li>镜像</li><li>宿主机和 workspace 路径</li><li>后台任务数</li><li>若配置了 CDI 设备，也会列出实际挂载的设备</li></ul><h2 id="进阶-cdi-设备" tabindex="-1">进阶：CDI 设备 <a class="header-anchor" href="#进阶-cdi-设备" aria-label="Permalink to &quot;进阶：CDI 设备&quot;">​</a></h2><p>要把宿主机通过 <strong>CDI</strong>（常见是 GPU）透进容器，在 <strong>Container</strong> -&gt; <strong>Advanced</strong> 里配。一般只有确实要在里面跑 CUDA/ROCm 等才要动。</p><h3 id="配法" tabindex="-1">配法 <a class="header-anchor" href="#配法" aria-label="Permalink to &quot;配法&quot;">​</a></h3><ol><li>打开 <strong>Container</strong>。</li><li>没有容器先 <strong>Create</strong>；要改 GPU 类设置往往要<strong>重建</strong>容器。</li><li>展开 <strong>Advanced</strong>。</li><li>开 <strong>GPU</strong>，在 <strong>CDI devices</strong> 里写设备名。</li></ol><p>可每行一个或逗号分隔，例如：</p><ul><li><code>nvidia.com/gpu=0</code></li><li><code>nvidia.com/gpu=all</code></li><li><code>amd.com/gpu=0</code></li><li><code>amd.com/gpu=all</code></li></ul><h3 id="宿主要求" tabindex="-1">宿主要求 <a class="header-anchor" href="#宿主要求" aria-label="Permalink to &quot;宿主要求&quot;">​</a></h3><p>宿主机上驱动、厂商工具、CDI spec 要已就绪。通常意味着：</p><ul><li>宿主机上 GPU 本来就能用</li><li><code>/etc/cdi</code> 或 <code>/var/run/cdi</code> 里有 spec</li><li>你填的名字和运行时看见的一致</li></ul><p>查本机名：</p><ul><li>NVIDIA：<code>nvidia-ctk cdi list</code></li><li>AMD：<code>amd-ctk cdi list</code></li></ul><p>若报 <code>unresolvable CDI devices</code>，多半是名字对不上。</p><h3 id="注意" tabindex="-1">注意 <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意&quot;">​</a></h3><ul><li>CDI 在<strong>创建</strong>时生效，改配置后常要<strong>重建</strong>容器；只停再起<strong>不会</strong>换已挂设备。</li><li>镜像里仍要装对的用户态库，才能真跑算子。</li><li>建好后 <strong>Container</strong> tab 会显示当前挂上的设备，便于核对。</li></ul><h2 id="快照" tabindex="-1">快照 <a class="header-anchor" href="#快照" aria-label="Permalink to &quot;快照&quot;">​</a></h2><p><strong>Create Snapshot</strong> 会记录当前容器 workspace 状态，方便回滚、版本化 runtime 或试大改。<strong>Restore</strong> 按某个快照回退，可删不要的快照。</p><h2 id="导入导出" tabindex="-1">导入导出 <a class="header-anchor" href="#导入导出" aria-label="Permalink to &quot;导入导出&quot;">​</a></h2><p><strong>Container</strong> tab 支持导入导出 workspace 数据：</p><ul><li><strong>Export Data</strong>：把 workspace 文件系统数据打成包下载。</li><li><strong>Import Data</strong>：从本地上传归档并解进 workspace 文件系统。</li><li><strong>Restore</strong>：在数据目录侧做“清到干净再灌”，适合盘坏了或想从零来而又不删 runtime 实例时。</li></ul><h2 id="版本" tabindex="-1">版本 <a class="header-anchor" href="#版本" aria-label="Permalink to &quot;版本&quot;">​</a></h2><p>Memoh 会跟踪 workspace/container 版本，帮助审计 runtime 环境何时、因何变过。</p>',41)])])}const u=a(i,[["render",l]]);export{g as __pageData,u as default};
